import type { DMMF } from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 */
function scalarTypeToTs(typeName: string): string {
  switch (typeName) {
    case 'String':
      return 'string'
    case 'Boolean':
      return 'boolean'
    case 'Int':
    case 'Float':
    case 'Decimal':
      return 'number'
    case 'BigInt':
      return 'bigint'
    case 'DateTime':
      return 'Date'
    case 'Json':
      return 'unknown'
    case 'Bytes':
      return 'Uint8Array'
    default:
      return 'unknown'
  }
}

/**
 * Returns the TypeScript type string for a DMMF field, accounting for
 * list and optional modifiers.
 */
export function fieldToTsType(field: DMMF.Field): string {
  let base: string
  if (field.kind === 'object') {
    base = field.type
  } else if (field.kind === 'enum') {
    base = field.type
  } else {
    base = scalarTypeToTs(field.type)
  }

  if (field.isList) {
    return `${base}[]`
  }

  if (!field.isRequired) {
    return `${base} | null`
  }

  return base
}

/**
 * Renders the TypeScript `interface` declaration for a Prisma model.
 * Relation fields (kind === 'object') are excluded; they are not part of
 * the wire representation returned by a REST endpoint.
 */
export function renderModelInterface(model: DMMF.Model): string {
  const fields = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = !f.isRequired ? '?' : ''
      return `  ${f.name}${optional}: ${fieldToTsType(f)}`
    })
    .join('\n')

  return `export interface ${model.name} {\n${fields}\n}`
}

/**
 * Renders the TypeScript `enum` declaration for a Prisma enum.
 */
export function renderEnum(dmmfEnum: DMMF.DatamodelEnum): string {
  const members = dmmfEnum.values.map((v) => `  ${v.name} = '${v.name}',`).join('\n')
  return `export enum ${dmmfEnum.name} {\n${members}\n}`
}

type IdInfo = {
  /** The TypeScript parameter declaration for the where-clause, e.g. `id: string`. */
  param: string
  /** The expression that extracts the ID value from `params.where`, e.g. `params.where.id`. */
  access: string
  /** The name of the ID field, used in `Omit<Model, 'fieldName'>`. */
  name: string
}

function resolveIdInfo(model: DMMF.Model): IdInfo {
  const idField = model.fields.find((f) => f.isId)
  if (idField) {
    return {
      param: `${idField.name}: ${fieldToTsType(idField)}`,
      access: `params.where.${idField.name}`,
      name: idField.name,
    }
  }
