    if (response.status === 404) return null
    if (!response.ok) throw new Error(\`GET \${this.baseUrl}/${resource}/...: \${response.status} \${response.statusText}\`)
    return response.json() as Promise<${name}>
  }

  async create(params: { data: Omit<${name}, '${id.name}'> }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!response.ok) throw new Error(\`POST \${this.baseUrl}/${resource}: \${response.status} \${response.statusText}\`)
    return response.json() as Promise<${name}>
  }

  async update(params: { where: { ${id.param} }; data: Partial<${name}> }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}/\${${id.access}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    if (!response.ok) throw new Error(\`PATCH \${this.baseUrl}/${resource}/...: \${response.status} \${response.statusText}\`)
    return response.json() as Promise<${name}>
  }

  async delete(params: { where: { ${id.param} } }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}/\${${id.access}}\`, {
      method: 'DELETE',
    })
    if (!response.ok) throw new Error(\`DELETE \${this.baseUrl}/${resource}/...: \${response.status} \${response.statusText}\`)
    return response.json() as Promise<${name}>
  }
