 * Renders the top-level `RestClient` interface that aggregates a typed
 * accessor for every model in the schema.
 */
export function renderRestClientInterface(models: readonly DMMF.Model[]): string {
  const properties = models
    .map((m) => {
      const name = m.name
      const camel = name.charAt(0).toLowerCase() + name.slice(1)
      const id = resolveIdInfo(m)
      return `  ${camel}: {
    findMany(params?: { skip?: number; take?: number }): Promise<${name}[]>
    findUnique(params: { where: { ${id.param} } }): Promise<${name} | null>
    create(params: { data: Omit<${name}, '${id.name}'> }): Promise<${name}>
    update(params: { where: { ${id.param} }; data: Partial<${name}> }): Promise<${name}>
    delete(params: { where: { ${id.param} } }): Promise<${name}>
  }`
    })
    .join('\n')

  return `export interface RestClient {\n${properties}\n}`
}

/**
 * Renders the `createRestClient` factory function that instantiates a
 * `RestClient` backed by concrete per-model HTTP clients.
 */
export function renderFactory(models: readonly DMMF.Model[]): string {
  const entries = models
    .map((m) => {
      const camel = m.name.charAt(0).toLowerCase() + m.name.slice(1)
      return `    ${camel}: new ${m.name}RestClient(baseUrl),`
    })
    .join('\n')

  return `\
export function createRestClient(baseUrl: string): RestClient {
  return {
${entries}
  }
}`
}

