import fs from 'node:fs/promises'
import path from 'node:path'

import type { DMMF } from '@prisma/dmmf'
import type { GeneratorOptions } from '@prisma/generator'

import {
  renderEnum,
  renderFactory,
  renderModelClient,
  renderModelInterface,
  renderRestClientInterface,
} from './template'

const FILE_HEADER = `\
// Generated by @prisma/generator-rest-client. Do not edit manually.
// Re-run \`prisma generate\` to regenerate this file.
`

/**
 * Entry point for REST client code generation.
 *
 * Reads model and enum definitions from `options.dmmf` and writes a single
 * `rest-client.ts` file to the configured output directory. The generated
 * file contains:
 *   - TypeScript `enum` declarations for every Prisma enum
 *   - TypeScript `interface` declarations for every Prisma model
 *   - Per-model client classes implementing typed CRUD over HTTP
 *   - A `RestClient` interface aggregating all per-model clients
 *   - A `createRestClient(baseUrl)` factory function
 */
export async function generate(options: GeneratorOptions): Promise<void> {
  const outputDir = options.generator.output?.value
  if (!outputDir) {
    throw new Error('Output directory is not configured. Set `output` in the generator block.')
  }

  await fs.mkdir(outputDir, { recursive: true })

  const content = buildFileContent(options.dmmf.datamodel)
  await fs.writeFile(path.join(outputDir, 'rest-client.ts'), content, 'utf-8')
}

function buildFileContent(datamodel: DMMF.Datamodel): string {
  const sections: string[] = [FILE_HEADER]

  for (const dmmfEnum of datamodel.enums) {
    sections.push(renderEnum(dmmfEnum))
  }

  for (const model of datamodel.models) {
    sections.push(renderModelInterface(model))
  }

  for (const model of datamodel.models) {
    sections.push(renderModelClient(model))
  }

  sections.push(renderRestClientInterface(datamodel.models))
  sections.push(renderFactory(datamodel.models))

  return sections.join('\n\n') + '\n'
}

